// ============================================================
// ENFORCE SANDBOX + FILTER ACTIVE CLIENTS
// NEVER routes to production unless environment='production'
// ============================================================

const clients = $input.all()
  .filter(item => String(item.json.active).toUpperCase() === 'TRUE')
  .map(item => {
    const cfg = item.json;
    const isProd = cfg.environment === 'production';

    const qbBaseUrl = isProd
      ? 'https://quickbooks.api.intuit.com'
      : 'https://sandbox-quickbooks.api.intuit.com';

    const qbPaymentLinkBase = isProd
      ? 'https://app.qbo.intuit.com'
      : 'https://sandbox.qbo.intuit.com';

    return {
      json: {
        ...cfg,
        qb_base_url: qbBaseUrl,
        qb_payment_link_base: qbPaymentLinkBase,
        effective_environment: cfg.environment || 'sandbox',
        qb_minor_version: parseInt(cfg.qb_minor_version || '73', 10)
      }
    };
  });

if (clients.length === 0) {
  throw new Error('No active clients found in Client_Master_Config. Check that active=TRUE for at least one row.');
}

console.log(`WF1 running for ${clients.length} active client(s): ${clients.map(c => c.json.client_name).join(', ')}`);
return clients;

// ============================================================
// MERGE CLIENT CONFIG + FRESH ACCESS TOKEN
// PLACEMENT: After 'Process & Store Fresh Token'.
// All downstream QB API nodes reference this node by name.
// ============================================================

const token = $input.first().json;
const config = $('Loop: Process Each Client').item.json;

if (!token.access_token) {
  throw new Error(`OAuth token missing for client: ${config.client_name}`);
}

return [{
  json: {
    ...config,
    access_token: token.access_token,
    authorization_header: `Bearer ${token.access_token}`,
    token_expires_at: token.expires_at,
    token_retrieved_at: token.retrieved_at
  }
}];

const token = $input.first().json;
const expiresAt = new Date(Date.now() + (token.expires_in || 3600) * 1000).toISOString();
const cfg = $('Loop: Process Each Client').item.json;

return [{
  json: {
    // Merged: all config fields + fresh token
    ...cfg,
    access_token: token.access_token,
    authorization_header: `Bearer ${token.access_token}`,
    token_expires_at: expiresAt,
    token_retrieved_at: new Date().toISOString()
  }
}];

// Returns empty array to trigger the next client loop iteration.
// Connect output → Loop: Process Each Client (input port).
return [];

// ============================================================
// ANALYZE WF1 ERROR
// Capture error context from the Loop's current client.
// ============================================================

const error = $input.first().json.error || $input.first().json;
const cfg = $('Loop: Process Each Client').item?.json || {};

const statusCode = error.statusCode || error.httpCode || 0;
const message = error.message || JSON.stringify(error);

const isRetriable = statusCode === 0
  || statusCode === 429
  || statusCode === 503
  || statusCode === 504;

const retryCount = parseInt(cfg.retry_count || '0', 10);

return [{
  json: {
    client_id: cfg.client_id || 'unknown',
    client_name: cfg.client_name || 'Unknown Client',
    slack_dev_channel_id: cfg.slack_dev_channel_id || '',
    data_sheet_id: cfg.data_sheet_id || '',
    error_log_gid: cfg.error_log_gid || '',
    status_code: statusCode,
    error_message: message,
    is_retriable: isRetriable,
    retry_count: retryCount,
    failed_at: new Date().toISOString(),
    workflow: 'WF1'
  }
}];

const item = $input.first().json;
const retryCount = (item.retry_count || 0) + 1;
return [{ json: { ...item, retry_count: retryCount, circuit_breaker_tripped: retryCount >= 3 } }];
